var e=[{id:`L3_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`마을의 상황은 어떻지?`,JPN:`村の状況はどうだ？`,ENG:`What's the situation in the village?`,TWN:`村子的情況怎麼樣了？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`온통 침식체들 뿐입니다. 발견된 주민들은 이미 모두 사망했습니다.`,JPN:`侵食体しかいません。発見された住民は全員死亡しました。`,ENG:`It's swarming with C.O.s. All the civilians are dead.`,TWN:`全是侵蝕體。目前發現的村民都已經死亡。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`수색 범위를 확대하도록. 아직 생존자가 있을 지도 모른다.`,JPN:`捜索範囲を拡大するように。まだ生存者がいるかもしれない。`,ENG:`Expand the search. There may still be survivors.`,TWN:`擴大搜索範圍，或許還有倖存者。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`저긴...... 버려진 교회인가?`,JPN:`あれは……放棄された教会か？`,ENG:`Is that... an abandoned church?`,TWN:`那裡是……被遺棄的教會嗎？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`꺄아아악!`,JPN:`きゃあああ！`,ENG:`Aaaaaaaagh!`,TWN:`呃啊啊阿！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`으윽...... 괴물 놈들......`,JPN:`うぅ……化け物め……`,ENG:`Ugh... You monsters...`,TWN:`呃……怪物們……`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`웃기지 마, 내가...... 이대로 죽을 것 같아?`,JPN:`ふざけるな、私は……こんなところでは死なない！`,ENG:`Don’t make me laugh... You think I'll die like this?`,TWN:`別開玩笑了，以為我會……就這麼死嗎？`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`괜찮은가? 꼬마.`,JPN:`大丈夫か、チビ。`,ENG:`You alright, kid?`,TWN:`你沒事吧？小朋友。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`......당신, 누구야?`,JPN:`……あなたは、誰？`,ENG:`Who are you?`,TWN:`……你，是誰？`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`다, 다가오지 마!`,JPN:`ち、近寄るな！`,ENG:`S-stay away!`,TWN:`別、別過來！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`경계심이 좋은 꼬마로군. 하지만 쓸데없는 짓이다.`,JPN:`警戒心があるのはいいことだ。だが今は必要ない。`,ENG:`Relax kid, relax. Don't worry, we're not here to harm you.`,TWN:`看來是個很有警戒心的小鬼啊。不過別掙扎了。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`우린 민간인들을 구출하러 온 구원부대다.`,JPN:`私たちは民間人を助けにきた救助部隊だ。`,ENG:`We're a rescue unit, here to evacuate civilians.`,TWN:`我們是來營救平民的救援部隊。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`귀찮게 반항할 필요는 없어...... 음?`,JPN:`抵抗する必要は……うむ？`,ENG:`You don't have to resist—hmm?`,TWN:`沒必要反抗造成麻煩……嗯？`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`이, 이 손 놔!`,JPN:`は、放してよ！`,ENG:`L-let go!`,TWN:`放開我的手！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`이 피부는...... 침식 증상이로군.`,JPN:`この皮膚は……侵食症状か。`,ENG:`The lesions on your skin... They are the symptom of Corruption Syndrome.`,TWN:`這皮膚……是侵蝕症狀。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};